import AsyncStorage from '@react-native-async-storage/async-storage';
import { Platform } from 'react-native';

const isProduction = __DEV__ === false;
const DEBUG_LEVEL = isProduction ? 'INFO' : 'DEBUG';

const Logger = {
  debug: (message, data = null) => {
    if (DEBUG_LEVEL === 'DEBUG') {
      console.debug(`[DEBUG] ${message}`, data);
    }
  },
  
  info: (message, data = null) => {
    console.info(`[INFO] ${message}`, data);
  },
  
  warn: (message, data = null) => {
    console.warn(`[WARN] ${message}`, data);
  },
  
  error: (message, data = null) => {
    console.error(`[ERROR] ${message}`, data);
  }
};

const Redactor = {
  redactToken: (token) => {
    if (!token) return null;
    return token.length > 10 
      ? `${token.substring(0, 5)}...${token.substring(token.length - 5)}`
      : '***';
  },
  
  redactSensitiveFields: (data) => {
    if (!data || typeof data !== 'object') return data;
    
    const redacted = { ...data };
    const sensitiveFields = ['password', 'token', 'auth', 'secret', 'credential', 'key'];
    
    for (const key in redacted) {
      if (sensitiveFields.some(field => key.toLowerCase().includes(field))) {
        redacted[key] = '***REDACTED***';
      }
    }
    
    return redacted;
  },
  
  redactUrlParams: (url) => {
    if (!url) return url;
    return url.replace(/(password|token|auth|secret)=([^&]+)/g, '$1=***REDACTED***');
  }
};

const NetworkLogger = {
  originalFetch: null,
  
  init() {
    if (this.originalFetch) return;
    
    this.originalFetch = global.fetch;
    
    global.fetch = async (url, options = {}) => {
      const startTime = Date.now();
      const requestId = Math.random().toString(36).substr(2, 9);
      
      const redactedUrl = Redactor.redactUrlParams(url);
      const redactedOptions = {
        ...options,
        headers: { ...options.headers }
      };
      
      if (redactedOptions.headers?.authorization) {
        redactedOptions.headers.authorization = `Bearer ${Redactor.redactToken(redactedOptions.headers.authorization.split(' ')[1])}`;
      }
      
      Logger.debug(`[FETCH] Request started: ${requestId}`, {
        url: redactedUrl,
        method: options.method || 'GET',
        headers: redactedOptions.headers,
        body: options.body ? '***REDACTED***' : null
      });
      
      try {
        const response = await this.originalFetch(url, options);
        const endTime = Date.now();
        const duration = endTime - startTime;
        
        const responseClone = response.clone();
        const responseText = await responseClone.text();
        
        Logger.debug(`[FETCH] Request completed: ${requestId}`, {
          url: redactedUrl,
          method: options.method || 'GET',
          status: response.status,
          statusText: response.statusText,
          duration: `${duration}ms`,
          responseSize: responseText.length,
          responseHeaders: {
            'content-type': response.headers.get('content-type'),
            'content-length': response.headers.get('content-length')
          }
        });
        
        return new Response(responseText, response);
      } catch (error) {
        Logger.error(`[FETCH] Request failed: ${requestId}`, {
          url: redactedUrl,
          method: options.method || 'GET',
          error: error.message,
          stack: isProduction ? null : error.stack
        });
        throw error;
      }
    };
  }
};

const AsyncStorageLogger = {
  originalSetItem: null,
  originalGetItem: null,
  originalRemoveItem: null,
  
  init() {
    if (this.originalSetItem) return;
    
    this.originalSetItem = AsyncStorage.setItem;
    this.originalGetItem = AsyncStorage.getItem;
    this.originalRemoveItem = AsyncStorage.removeItem;
    
    AsyncStorage.setItem = async (key, value) => {
      Logger.debug('[ASYNC_STORAGE] SET', {
        key: key,
        value: Redactor.redactSensitiveFields(JSON.parse(value))
      });
      return this.originalSetItem(key, value);
    };
    
    AsyncStorage.getItem = async (key) => {
      Logger.debug('[ASYNC_STORAGE] GET', { key });
      return this.originalGetItem(key);
    };
    
    AsyncStorage.removeItem = async (key) => {
      Logger.debug('[ASYNC_STORAGE] REMOVE', { key });
      return this.originalRemoveItem(key);
    };
  }
};

const UserActionLogger = {
  actions: [],
  maxActions: 100,
  
  logAction(action, data = null) {
    const actionEntry = {
      timestamp: new Date().toISOString(),
      action,
      data: Redactor.redactSensitiveFields(data)
    };
    
    this.actions.push(actionEntry);
    
    if (this.actions.length > this.maxActions) {
      this.actions.shift();
    }
    
    Logger.debug('[USER_ACTION]', actionEntry);
  },
  
  getRecentActions() {
    return this.actions;
  }
};

const StateLogger = {
  logStateChange(prevState, nextState, action) {
    Logger.debug('[STATE_CHANGE]', {
      action,
      previous: Redactor.redactSensitiveFields(prevState),
      current: Redactor.redactSensitiveFields(nextState)
    });
  }
};

const AuthLogger = {
  logLogin(token, userData) {
    Logger.info('[AUTH] User logged in', {
      token: Redactor.redactToken(token),
      userId: userData?.id,
      email: userData?.email ? userData.email.split('@')[0] + '@***' : null
    });
  },
  
  logLogout() {
    Logger.info('[AUTH] User logged out');
  }
};

const DebugModule = {
  init() {
    if (isProduction) {
      Logger.info('Debug module initialized in production mode');
      return;
    }
    
    NetworkLogger.init();
    AsyncStorageLogger.init();
    
    Logger.info('Debug module initialized');
  },
  
  logUserAction(action, data = null) {
    UserActionLogger.logAction(action, data);
  },
  
  logStateChange(prevState, nextState, action) {
    StateLogger.logStateChange(prevState, nextState, action);
  },
  
  logAuthLogin(token, userData) {
    AuthLogger.logLogin(token, userData);
  },
  
  logAuthLogout() {
    AuthLogger.logLogout();
  },
  
  getDebugInfo() {
    return {
      actions: UserActionLogger.getRecentActions(),
      timestamp: new Date().toISOString()
    };
  }
};

export default DebugModule;